8e44d67c  export function assemblePrompt(opts: {
802fa942  	profileSystemMd: string;
fda0b3a9  	agentsMd: string | null;
8ba6b482  	agentsMdPath: string | null;
4f8e7216  	toolDefsText: string;
b546a509  	userPrompt?: string;
81a0f018  }): AssembledPrompt {
24b52338  	const systemText = opts.profileSystemMd;
42662473  	const agentsText = opts.agentsMd ?? "";
a53222ef  	const toolDefsText = opts.toolDefsText;
3e8ebb67  	const userText = opts.userPrompt ?? "";
e3b0c442  
6b237c07  	const layers: AssembledPromptLayer[] = [
3a763367  		{
53711809  			name: "system.md",
a353d92b  			tokens_approx: Math.ceil(systemText.length / 4),
0a612911  			present: systemText.length > 0,
b7fa8888  		},
3a763367  		{
888d2ff6  			name: "AGENTS.md",
20224b72  			tokens_approx: opts.agentsMd === null ? 0 : Math.ceil(agentsText.length / 4),
4057e179  			present: opts.agentsMd !== null,
b7fa8888  		},
3a763367  		{
bd6a980a  			name: "tool_defs",
ba8a9781  			tokens_approx: Math.ceil(toolDefsText.length / 4),
